ore:'Load backup? Current data will be overwritten!',co_t:'📚 Sleep Course',co_sub:'14-day baby sleep guide – science-based, attachment-oriented.',co_prog:'of 8 chapters completed',co_read:'min read',tr_s7:'Sleep last 7 days',tr_ww:'Wake window trend',tr_nw:'Night wakings (7 days)',tr_algo:'🧠 Algorithm',tr_tot:'Total sleep',tr_avg:'∅ Wake window',tr_long:'Longest sleep',hi_t:'📋 All entries',hi_all:'All',hi_n:'entries',rp_pt:'Patient data',rp_nm:'Name',rp_bd:'Date of birth',rp_age:'Age',wo:'Săpt',day:'zile',hr:'ore',co1_t:'Ferestre de veghe',co1_s:'Baza somnului bun',co1_d:'1 min',co1_c:'<b>Ferestrele de veghe</b> sunt perioadele cand bebelusul sta treaz. Ca o baterie: culcati-l cand e joasa!<br><br>Nou-nascuti 30-60 min, 6 luni 2-3h.<br><br><b>Sfat:</b> Prima fereastra e cea mai scurta!',co2_t:'Presiunea somnului',co2_s:'De ce obosesc bebelusii',co2_d:'1 min',co2_c:'<b>Adenozina</b> se acumuleaza.<br><br><b>Prea devreme:</b> Putina presiune, somnuri scurte.<br><b>Prea tarziu:</b> Cortizol, suprastimulare.',co3_t:'Semne de oboseala',co3_s:'Limbajul bebelusului',co3_d:'2 min',co3_c:'<b>Timpurii:</b> Mai putin contact vizual, cascat.<br><b>Tarzii:</b> Plans, arcuire.<br><br>De la 4 luni semnele devin subtile.',co4_t:'Ritmul zi-noapte',co4_s:'Structura pentru nopti mai bune',co4_d:'3 min',co4_c:'<b>Dimineata:</b> Aceeasi ora, lumina!<br><b>Ziua:</b> Ferestre, lumina si aer.<br><b>Seara:</b> Lumina slaba 1h inainte.<br><b>Noapte:</b> Alaptare pe intuneric.',co5_t:'Mediul de somn',co5_s:'Spatiul perfect',co5_d:'2 min',co5_c:'<b>Temperatura:</b> 16-18°C.<br><b>Intuneric:</b> Maxim. Doar lumina rosie.<br><b>Zgomot:</b> Zgomot alb 50-65 dB.<br><b>Siguranta:</b> Pe spate, sac de dormit.',co6_t:'Tranzitii somnuri',co6_s:'Cand totul se schimba',co6_d:'3 min',co6_c:'Tranzitii: 5-6 la 3-4 la 2-3 la 2 la 1. 2-4 saptamani.<br><br><b>Semne:</b> Protest, somnuri scurte. Zile rele = normale!',co7_t:'Treziri nocturne',co7_s:'De ce e normal',co7_d:'2 min',co7_c:'<b>Toti</b> bebelusii se trezesc! Foame, cicluri scurte, salturi.<br><br><b>Ajutor:</b> Pauza 30-60 sec. Poate adormi singur.',co8_t:'Regresie 4 luni',co8_s:'Marea schimbare',co8_d:'3 min',co8_c:'La 3-5 luni tiparele se schimba.<br><br><b>Simptome:</b> Somn prost, treziri frecvente.<br><br><b>Ajutor:</b> Scurtati ferestrele, pastrati rutina. 2-6 saptamani.',co9_t:'Regresie 8-10 luni',co9_s:'Mobilitate si anxietate',co9_d:'2 min',co9_c:'Abilitati noi perturba somnul. Anxietate de separare.<br><br><b>Ajutor:</b> Practica ziua, apropiere extra.',co10_t:'Alaptare si somn',co10_s:'Intelegerea legaturii',co10_d:'3 min',co10_c:'Laptele matern contine mai multa melatonina seara!<br><br><b>Cluster:</b> Normal seara.<br><b>Nocturna:</b> Necesara inainte de 6 luni.',co11_t:'Diversificare si somn',co11_s:'Introducerea solidelor',co11_d:'2 min',co11_c:'De la 6 luni diversificarea poate imbunatati somnul.<br><br><b>Timing:</b> Alimente noi dimineata.',co12_t:'Construirea rutinei',co12_s:'7 pasi spre ritual',co12_d:'3 min',co12_c:'Rutina semnaleaza: e timpul somnului.<br><br><b>Exemplu (20 min):</b> Scutec si pijama, intuneric, sac, cantec/carte, imbratisare, sunete, culcare.',co13_t:'Impreuna',co13_s:'Ca pereche prin nopti',co13_d:'2 min',co13_c:'<b>Ture:</b> 20-2 / 2-7.<br><b>Partajare:</b> Ambii vad intrarile prin sync.<br><br>Provocari <b>in afara</b> dormitorului.',co14_t:'Bunastarea parintilor',co14_s:'Si tu contezi!',co14_d:'2 min',co14_c:'Dormi cand doarme bebelusul. Cere ajutor. Iesi la aer.<br><br><b>Te descurci excelent.</b> Fiecare faza trece!',s_title:'⚙️ Setari',s_babyname:'Numele bebelusului',s_age:'Varsta',s_algophase:'Faza algoritmului',s_starttrack:'Incepe urmarirea',s_version:'Versiune',s_info:'Info',sweet_dreams:'Vise dulci...',now_tired:'Obosit!',put_down_now:'Culcati acum!',bedtime_reached:'E ora de somn!',p_next_approx:'Urmatorul somn aprox.',p_ref:'Interval tinta',slot_morning:'Dimineata',slot_noon:'Pranz',slot_afternoon:'Dupa-amiaza',slot_bedtime:'Somn',algo_info:'Info algoritm',a