let _lang=localStorage.getItem('bs3_lang')||'de';
function t(k){return (I[_lang]&&I[_lang][k])||I.en[k]||I.de[k]||k}
function setLang(code){_lang=code;localStorage.setItem('bs3_lang',code);applyLang()}
function applyLang(){
  // Nav
  document.querySelectorAll('.ni[data-s]').forEach(b=>{
    const k='nav_'+b.dataset.s;const lbl=b.querySelector('.nil');
    if(lbl&&t(k)!==k)lbl.textContent=t(k)});
  // All data-t attributes
  document.querySelectorAll('[data-t]').forEach(el=>{
    const k=el.dataset.t;if(t(k)!==k)el.textContent=t(k)});
  // All data-tp (placeholder)
  document.querySelectorAll('[data-tp]').forEach(el=>{
    const k=el.dataset.tp;if(t(k)!==k)el.placeholder=t(k)});
  // RTL for Arabic/Hebrew/Farsi/Urdu
  const rtl=['ar','he','fa','ur'];
  document.body.dir=rtl.includes(_lang)?'rtl':'ltr';
  // Update lang selector display
  const ls=document.getElementById('lang-sel');
  if(ls){const l=LANGS.find(x=>x.code===_lang);if(l)ls.textContent=l.flag+' '+l.name}
}
