  const dur=Math.round((Date.now()-c.sleepStart)/6e4);
  c.entries.push({type:'sleep',sub:dur>120?'night':'nap',ts:c.sleepStart,dur,id:Date.now().toString()});
  c.isSleeping=false;c.sleepStart=null;save();updateAll();toast(`☀️ ${dur} ${t('t_slept')}`);schedNotif();
milkInitPush();
tutAutoStart();
  // Smart push: "Noch wach?" nach erwartetem Wachfenster
  schedWakeCheck();
