// ===== SMART PUSH NOTIFICATIONS =====
let smartPushTimers={};

function schedSleepCheck(c){
  clearTimeout(smartPushTimers.sleep1);clearTimeout(smartPushTimers.sleep2);
  if(!('Notification' in window)||Notification.permission!=='granted')return;
  const name=c?.name||'Baby';
  // After 1h: still sleeping?
  smartPushTimers.sleep1=setTimeout(()=>{
    if(C()?.isSleeping)new Notification('💤 '+name,{body:t('sp_still_sleeping')||'Schläft noch? Tippe um aufzuwecken.',tag:'sleep-check'});
  },60*60*1000);
  // After 2h: reminder
  smartPushTimers.sleep2=setTimeout(()=>{
    if(C()?.isSleeping)new Notification('⏰ '+name,{body:t('sp_long_sleep')||'Schon 2h Schlaf! Aufwecken?',tag:'sleep-check2'});
  },120*60*1000);
}

function schedNurseCheck(){
  clearTimeout(smartPushTimers.nurse);
  if(!('Notification' in window)||Notification.permission!=='granted')return;
  const name=C()?.name||'Baby';
  // After 15min: still nursing?
  smartPushTimers.nurse=setTimeout(()=>{
    if(swState.running)new Notification('🤱 '+name,{body:t('sp_still_nursing')||'Stillst du noch?',tag:'nurse-check'});
  },15*60*1000);
}

function schedWakeCheck(){
  clearTimeout(smartPushTimers.wake);
  if(!('Notification' in window)||Notification.permission!=='granted')return;
  const pred=predictNap();if(!pred)return;
  const name=C()?.name||'Baby';
  // 30min before predicted nap
  const msUntil=pred.nextNapMs-(30*60*1000);
  if(msUntil>0&&msUntil<4*3600000){
    smartPushTimers.wake=setTimeout(()=>{
      if(!C()?.isSleeping)new Notification('👀 '+name,{body:t('sp_still_awake')||'Noch wach? Bald müde!',tag:'wake-check'});
    },msUntil);
  }
}
