// ===== NURSING STOPWATCH =====
let swState={running:false,side:null,startTime:0,elapsed:0,L:0,R:0,interval:null,sideStart:0};
let wakeLock=null;

// Wake Lock: keep screen on during nursing
async function swWakeLock(on){
  try{
    if(on&&'wakeLock' in navigator){
      wakeLock=await navigator.wakeLock.request('screen');
      wakeLock.addEventListener('release',()=>{wakeLock=null});
    }else if(!on&&wakeLock){wakeLock.release();wakeLock=null}
  }catch(e){console.log('WakeLock:',e)}
}
// Re-acquire wake lock on visibility change (iOS loses it when tab hidden)
document.addEventListener('visibilitychange',()=>{
  if(document.visibilityState==='visible'&&swState.running)swWakeLock(true);
});

// Media Session: lock screen controls
function swMediaSession(on){
  if(!('mediaSession' in navigator))return;
  if(on){
    navigator.mediaSession.metadata=new MediaMetadata({title:'🤱 '+t('h_nurse'),artist:'babyAlex',album:t('f_nurse_hint')||''});
    navigator.mediaSession.playbackState='playing';
    navigator.mediaSession.setActionHandler('pause',()=>swPause());
    navigator.mediaSession.setActionHandler('play',()=>swToggle());
    navigator.mediaSession.setActionHandler('previoustrack',()=>swSide('L'));
    navigator.mediaSession.setActionHandler('nexttrack',()=>swSide('R'));
  }else{
    navigator.mediaSession.playbackState='none';
    try{navigator.mediaSession.setActionHandler('pause',null);navigator.mediaSession.setActionHandler('play',null);
    navigator.mediaSession.setActionHandler('previoustrack',null);navigator.mediaSession.setActionHandler('nexttrack',null)}catch(e){}
  }
}

function swUpdateBtnStates(){
  const L=el('sw-L'),R=el('sw-R');
  if(!swState.side){L.classList.remove('act','inactive');R.classList.remove('act','inactive')}
  else{
    L.classList.toggle('act',swState.side==='L');R.classList.toggle('act',swState.side==='R');
    L.classList.toggle('inactive',swState.side!=='L');R.classList.toggle('inactive',swState.side!=='R');
  }
  const hint=el('sw-hint');if(hint)hint.style.display=swState.running?'block':'block';
}

function swSide(s){
  if(!swState.running){
    // Allow pre-selecting side before start
    swState.side=s;swUpdateBtnStates();return;
  }
  if(swState.side===s)return;
  if(swState.side){swState[swState.side]+=Date.now()-swState.sideStart}
  swState.side=s;swState.sideStart=Date.now();
  swUpdateBtnStates();
  // Haptic feedback
  if(navigator.vibrate)navigator.vibrate(30);
}
function swBtnState(mode){
  // mode: 'idle','running','paused'
  const startBtn=el('sw-start'),pauseBtn=el('sw-pause'),stopBtn=el('sw-stop');
  if(mode==='idle'){
    startBtn.style.display='';startBtn.textContent='▶ Start';
    pauseBtn.style.display='none';stopBtn.style.display='none';
  }else if(mode==='running'){
    startBtn.style.display='none';
    pauseBtn.style.display='';pauseBtn.textContent='⏸ Pause';
    stopBtn.style.display='';
  }else if(mode==='paused'){
    startBtn.style.display='';startBtn.textContent='▶ Weiter';
    pauseBtn.style.display='none';
    stopBtn.style.display='';
  }
}
function swStart(){
  if(swState.running)return;
  if(swState.paused){
    // Resume from pause
    swState.running=true;swState.paused=false;
    if(swState.side)swState.sideStart=Date.now();
    swState.interval=setInterval(swUpdate,500);
    swBtnState('running');
    swWakeLock(true);swMediaSession(true);
    return;
  }
  // Fresh start
  swState.running=true;swState.paused=false;
  if(!swState.startTime){swState.startTime=Date.now();autoStopSleep();schedNurseCheck()}
  if(swState.side)swState.sideStart=Date.now();
  else{swState.side='L';swState.sideStart=Date.now()}
  swUpdateBtnStates();
  swState.interval=setInterval(swUpdate,500);
  swBtnState('running');
  swWakeLock(true);swMediaSession(true);
}
function swPause(){
  if(!swState.running)return;
  // Pause: stop timer, save side time, but keep state
  if(swState.side){swState[swState.side]+=Date.now()-swState.sideStart}
  swState.elapsed=Date.now()-swState.startTime;
  clearInterval(swState.interval);swState.interval=null;
  swState.running=false;swState.paused=true;
  swBtnState('paused');
  swWakeLock(false);
  // Auto-save on pause
  swAutoSave();
  if(navigator.vibrate)navigator.vibrate(50);
}
function swAutoSave(){
  // Save intermediate state to localStorage
  const totalMs=swState.elapsed||(swState.startTime?Date.now()-swState.startTime:0);
  if(totalMs<5000)return;
  localStorage.setItem('bs_nurse_state',JSON.stringify({
    startTime:swState.startTime,L:swState.L,R:swState.R,side:swState.side,
    elapsed:swState.elapsed,paused:swState.paused,ts:Date.now()
  }));
}
// Legacy alias for media session
function swToggle(){if(swState.running)swPause();else swStart()}
function swUpdate(){
  const elp=Date.now()-swState.startTime;const m=Math.floor(elp/6e4),s2=Math.floor(elp%6e4/1000);
  el('sw-time').textContent=`${p2(m)}:${p2(s2)}`;
  const lMs=swState.L+(swState.side==='L'?Date.now()-swState.sideStart:0);
  const rMs=swState.R+(swState.side==='R'?Date.now()-swState.sideStart:0);
  el('sw-tL').textContent=`${Math.floor(lMs/6e4)}:${p2(Math.floor(lMs%6e4/1000))}`;
  el('sw-tR').textContent=`${Math.floor(rMs/6e4)}:${p2(Math.floor(rMs%6e4/1000))}`;
  // Update mini-pill if visible
  nurseUpdateMini();
  // Update media session position
  if('mediaSession' in navigator&&navigator.mediaSession.setPositionState){
    try{navigator.mediaSession.setPositionState({duration:3600,position:Math.min(elp/1000,3599)})}catch(e){}
  }
}
function swReset(){clearInterval(swState.interval);swWakeLock(false);swMediaSession(false);
  swState={running:false,paused:false,side:null,startTime:0,elapsed:0,L:0,R:0,interval:null,sideStart:0};
  el('sw-time').textContent='00:00';el('sw-tL').textContent='0:00';el('sw-tR').textContent='0:00';
  swUpdateBtnStates();swBtnState('idle');
  document.getElementById('nurse-mini').style.display='none';
  localStorage.removeItem('bs_nurse_state')}
function saveNurse(){
  const c=C();if(!c)return;
  const totalMs=swState.elapsed||(swState.startTime?Date.now()-swState.startTime:0);
  if(totalMs<5000){toast('⚠️ Erst Stoppuhr starten!');return}
  const dur=Math.round(totalMs/6e4);
  const lDur=Math.round((swState.L+(swState.side==='L'&&swState.running?Date.now()-swState.sideStart:0))/6e4);
  const rDur=Math.round((swState.R+(swState.side==='R'&&swState.running?Date.now()-swState.sideStart:0))/6e4);
  c.entries.push({type:'feed',sub:'breast',ts:swState.startTime||Date.now(),dur,left:lDur,right:rDur,id:Date.now().toString()});
  swReset();save();updateAll();closeForms();toast(`🤱 ${t('f_breast')}: ${dur} ${t('p_min')} (${t('f_left')[0]}:${lDur}/${t('f_right')[0]}:${rDur})`)}



// ===== PUMP TIMER =====
let pumpSt={running:false,paused:false,side:null,startTime:0,elapsed:0,L:0,R:0,B:0,iv:null,sideStart:0};

function pumpBtnVis(m){
  const s=el('pump-start'),p=el('pump-pause-btn'),st=el('pump-stop');
  if(m==='idle'){s.style.display='';s.textContent='\u25b6 Start';p.style.display='none';st.style.display='none'}
  else if(m==='running'){s.style.display='none';p.style.display='';st.style.display=''}
  else{s.style.display='';s.textContent='\u25b6 Weiter';p.style.display='none';st.style.display=''}
}
function pumpSide(s){
  if(!pumpSt.running){pumpSt.side=s;pumpUpdSides();return}
  if(pumpSt.side===s)return;
  if(pumpSt.side)pumpSt[pumpSt.side]+=Date.now()-pumpSt.sideStart;
  pumpSt.side=s;pumpSt.sideStart=Date.now();pumpUpdSides();
  if(navigator.vibrate)navigator.vibrate(30);
}
function pumpUpdSides(){['L','R','B'].forEach(s=>{const b=el('pump-'+s);if(!b)return;if(!pumpSt.side){b.classList.remove('act','inactive')}else{b.classList.toggle('act',pumpSt.side===s);b.classList.toggle('inactive',pumpSt.side!==s)}})}
function pumpStart(){
  if(pumpSt.running)return;
  if(pumpSt.paused){pumpSt.running=true;pumpSt.paused=false;if(pumpSt.side)pumpSt.sideStart=Date.now();pumpSt.iv=setInterval(pumpUpd,500);pumpBtnVis('running');swWakeLock(true);return}
  pumpSt.running=true;pumpSt.paused=false;
  if(!pumpSt.startTime)pumpSt.startTime=Date.now();
  if(pumpSt.side)pumpSt.sideStart=Date.now();else{pumpSt.side='B';pumpSt.sideStart=Date.now()}
  pumpUpdSides();pumpSt.iv=setInterval(pumpUpd,500);pumpBtnVis('running');swWakeLock(true);
}
function pumpPauseFn(){
  if(!pumpSt.running)return;
  if(pumpSt.side)pumpSt[pumpSt.side]+=Date.now()-pumpSt.sideStart;
  pumpSt.elapsed=Date.now()-pumpSt.startTime;clearInterval(pumpSt.iv);
  pumpSt.running=false;pumpSt.paused=true;pumpBtnVis('paused');swWakeLock(false);
  if(navigator.vibrate)navigator.vibrate(50);
}
function pumpUpd(){
  const e=Date.now()-pumpSt.startTime;
  el('pump-time').textContent=p2(Math.floor(e/6e4))+':'+p2(Math.floor(e%6e4/1000));
  ['L','R','B'].forEach(s=>{const ms=pumpSt[s]+(pumpSt.side===s&&pumpSt.running?Date.now()-pumpSt.sideStart:0);const te=el('pump-t'+s);if(te)te.textContent=Math.floor(ms/6e4)+':'+p2(Math.floor(ms%6e4/1000))});
}
function pumpReset(){
  clearInterval(pumpSt.iv);swWakeLock(false);
  pumpSt={running:false,paused:false,side:null,startTime:0,elapsed:0,L:0,R:0,B:0,iv:null,sideStart:0};
  el('pump-time').textContent='00:00';['L','R','B'].forEach(s=>{const te=el('pump-t'+s);if(te)te.textContent='0:00'});
  el('pump-ml').value='';pumpUpdSides();pumpBtnVis('idle');
}
function pumpCalc(){
  const l=pumpSt.L+(pumpSt.side==='L'&&pumpSt.running?Date.now()-pumpSt.sideStart:0);
  const r=pumpSt.R+(pumpSt.side==='R'&&pumpSt.running?Date.now()-pumpSt.sideStart:0);
  const b=pumpSt.B+(pumpSt.side==='B'&&pumpSt.running?Date.now()-pumpSt.sideStart:0);
  const tot=pumpSt.startTime?Date.now()-pumpSt.startTime:0;
  return{tot,dur:Math.round(tot/6e4),lMin:Math.round(l/6e4),rMin:Math.round(r/6e4),bMin:Math.round(b/6e4)};
}
function pumpStopAsk(){
  if(!pumpSt.startTime)return;
  const d=pumpCalc(),ml=el('pump-ml').value||'?';
  el('pump-confirm-info').textContent=d.dur+' Min | '+ml+' ml';
  el('pump-confirm').classList.add('show');
}
function pumpStopConfirmed(){el('pump-confirm').classList.remove('show');savePump()}
function pumpCloseAsk(){
  if(!pumpSt.startTime||(!pumpSt.running&&!pumpSt.paused&&pumpSt.L===0&&pumpSt.R===0&&pumpSt.B===0)){pumpReset();closeForms();return}
  const d=pumpCalc();el('pump-close-info').textContent=d.dur+' Min | '+(el('pump-ml').value||'?')+' ml';
  el('pump-close-confirm').classList.add('show');
}
function pumpCloseSave(){el('pump-close-confirm').classList.remove('show');savePump()}
function pumpCloseDiscard(){el('pump-close-confirm').classList.remove('show');pumpReset();closeForms();toast('🗑 Abpumpen verworfen')}

function savePump(){
  const ch=C();if(!ch)return;
  const d=pumpCalc();if(d.tot<5000){toast('\u26a0\ufe0f Erst Timer starten!');return}
  const ml=parseInt(el('pump-ml').value)||0;
  const store=document.querySelector('#pi-pump-store .pill.sel')?.dataset.v||'fridge';
  const code=milkGenCode();
  // Save pump entry
  ch.entries.push({type:'feed',sub:'pump',ts:pumpSt.startTime,dur:d.dur,ml,left:d.lMin,right:d.rMin,both:d.bMin,id:Date.now().toString()});
  // Auto-create milk storage if store != none
  if(store!=='none'&&ml>0){
    if(!ch.milkStore)ch.milkStore=[];
    ch.milkStore.push({code,ml,ts:Date.now(),store,status:'active',moves:[{to:store,at:Date.now()}],note:''});
    milkSchedulePush(ch.milkStore[ch.milkStore.length-1],ch);
  }
  pumpReset();save();updateAll();closeForms();
  const msg='🧴 '+d.dur+' Min, '+ml+' ml'+(store!=='none'?' | Code: '+code:'');
  toast(msg);
}

// ===== MILK STORAGE SYSTEM =====
// CDC Guidelines: Room 4h, Fridge 4d(96h), Freezer 6mo(4320h), Thawed 24h
const MILK_LIMITS={room:4*3600000,fridge:96*3600000,freezer:4320*3600000,thawed:24*3600000};
const MILK_AMPEL={
  room:{green:2*3600000,yellow:3*3600000,red:4*3600000},
  fridge:{green:48*3600000,yellow:72*3600000,red:96*3600000},
  freezer:{green:120*24*3600000,yellow:150*24*3600000,red:180*24*3600000},
  thawed:{green:12*3600000,yellow:18*3600000,red:24*3600000}
};

function milkGenCode(){
  const d=new Date();
  const dd=p2(d.getDate()),mm=p2(d.getMonth()+1);
  const ch=C();
  const today=dd+mm;
  const existing=(ch?.milkStore||[]).filter(m=>m.code.startsWith('M-'+today)).length;
  return 'M-'+today+'-'+(existing+1);
}

function milkAddNew(){
  el('mk-add-btn').style.display='none';
  const form=el('mk-form');form.style.display='';
  // Set current datetime
  const now=new Date();
  const iso=now.getFullYear()+'-'+p2(now.getMonth()+1)+'-'+p2(now.getDate())+'T'+p2(now.getHours())+':'+p2(now.getMinutes());
  el('mk-dt').value=iso;
  el('mk-ml').value='';el('mk-note').value='';
}

function milkSaveNew(){
  const ch=C();if(!ch)return;
  const ml=parseInt(el('mk-ml').value);
  if(!ml||ml<=0){toast('\u26a0\ufe0f Menge eingeben!');return}
  const dt=new Date(el('mk-dt').value).getTime()||Date.now();
  const store=document.querySelector('#pi-mks .pill.sel')?.dataset.v||'fridge';
  const note=el('mk-note').value.trim();
  const code=milkGenCode();
  if(!ch.milkStore)ch.milkStore=[];
  const portion={code,ml,ts:dt,store,status:'active',moves:[{to:store,at:dt}],note};
  ch.milkStore.push(portion);
  milkSchedulePush(portion,ch);
  save();
  el('mk-form').style.display='none';el('mk-add-btn').style.display='';
  milkRender();
  toast('🧴 '+code+' | '+ml+' ml | '+(store==='fridge'?'\u2744\ufe0f':store==='freezer'?'🧊':'🌡\ufe0f'));
}

function milkGetState(portion){
  if(portion.status==='used')return{color:'used',label:'\u2705 Verbraucht',pct:100,remaining:0};
  if(portion.status==='discarded')return{color:'expired',label:'🗑 Entsorgt',pct:100,remaining:0};
  // Current storage type
  const lastMove=portion.moves[portion.moves.length-1];
  const storeType=lastMove.to;
  const storeStart=lastMove.at;
  const elapsed=Date.now()-storeStart;
  const limit=MILK_LIMITS[storeType]||MILK_LIMITS.fridge;
  const ampel=MILK_AMPEL[storeType]||MILK_AMPEL.fridge;
  const remaining=Math.max(0,limit-elapsed);
  const pct=Math.min(100,(elapsed/limit)*100);
  let color='green';
  if(elapsed>=limit)color='expired';
  else if(elapsed>=ampel.red*.95)color='red';
  else if(elapsed>=ampel.yellow)color='yellow';
  // Label
  let label='';
  if(color==='expired'){label='\u26a0\ufe0f Abgelaufen!'}
  else{
    const rH=Math.floor(remaining/3600000);
    const rD=Math.floor(rH/24);
    if(rD>0)label='Noch '+rD+'T '+Math.floor(rH%24)+'h';
    else if(rH>0)label='Noch '+rH+'h '+Math.floor((remaining%3600000)/60000)+'min';
    else label='Noch '+Math.floor(remaining/60000)+' min';
  }
  return{color,label,pct,remaining,storeType,storeStart,elapsed};
}

function milkRender(){
  const ch=C();if(!ch)return;
  const list=el('mk-list'),empty=el('mk-empty');
  if(!ch.milkStore||!ch.milkStore.length){list.innerHTML='';empty.style.display='';return}
  empty.style.display='none';
  // Sort: active first (by urgency), then used/discarded
  const sorted=[...ch.milkStore].sort((a,b)=>{
    const sa=a.status==='active'?0:1,sb=b.status==='active'?0:1;
    if(sa!==sb)return sa-sb;
    if(sa===0){return milkGetState(a).remaining-milkGetState(b).remaining}
    return b.ts-a.ts;
  });
  let html='';
  for(const m of sorted){
    const st=milkGetState(m);
    const storeIcon=m.store==='fridge'?'\u2744\ufe0f':m.store==='freezer'?'🧊':'🌡\ufe0f';
    const lastStore=(m.moves[m.moves.length-1]?.to)||m.store;
    const curIcon=lastStore==='fridge'?'\u2744\ufe0f':lastStore==='freezer'?'🧊':lastStore==='thawed'?'\u2744\ufe0f\u27a1\ufe0f🌡\ufe0f':'🌡\ufe0f';
    const dateStr=new Date(m.ts).toLocaleDateString('de-AT',{day:'2-digit',month:'2-digit',hour:'2-digit',minute:'2-digit'});
    const barColor=st.color==='green'?'#4CAF50':st.color==='yellow'?'#FFC107':st.color==='red'?'#F44336':'#9E9E9E';
    html+='<div class="mk-card">';
    html+='<div class="mk-head"><span class="mk-code">'+curIcon+' '+m.code+'</span><span class="mk-badge '+st.color+'">'+st.label+'</span></div>';
    html+='<div class="mk-info"><span>💧 '+m.ml+' ml</span><span>📅 '+dateStr+'</span>'+(m.note?'<span>📝 '+m.note+'</span>':'')+'</div>';
    if(m.status==='active'){
      html+='<div class="mk-bar"><div class="mk-bar-fill" style="width:'+st.pct+'%;background:'+barColor+'"></div></div>';
      html+='<div class="mk-acts">';
      if(lastStore==='freezer')html+='<button onclick="milkMove(\''+m.code+'\',\'thawed\')">\u2744\ufe0f\u27a1\ufe0f Auftauen</button>';
      if(lastStore==='fridge'||lastStore==='thawed')html+='<button onclick="milkMove(\''+m.code+'\',\'room\')">🌡\ufe0f Rausnehmen</button>';
      html+='<button onclick="milkUse(\''+m.code+'\')">\u2705 Verbraucht</button>';
      html+='<button onclick="milkDiscard(\''+m.code+'\')">🗑 Entsorgt</button>';
      html+='<button onclick="milkShowLabel(\''+m.code+'\')">🏷\ufe0f Etikett</button>';
      html+='</div>';
    }
    html+='</div>';
  }
  list.innerHTML=html;
}

function milkFind(code){const ch=C();return ch?.milkStore?.find(m=>m.code===code)}
function milkMove(code,to){
  const m=milkFind(code);if(!m)return;
  m.moves.push({to,at:Date.now()});
  m.store=to;// Update convenience field
  milkSchedulePush(m,C());
  save();milkRender();
  const icons={fridge:'\u2744\ufe0f',freezer:'🧊',room:'🌡\ufe0f',thawed:'\u2744\ufe0f\u27a1\ufe0f'};
  toast((icons[to]||'')+' '+code+' verschoben');
}
function milkUse(code){const m=milkFind(code);if(!m)return;m.status='used';save();milkRender();toast('\u2705 '+code+' verbraucht')}
function milkDiscard(code){const m=milkFind(code);if(!m)return;m.status='discarded';save();milkRender();toast('🗑 '+code+' entsorgt')}

function milkShowLabel(code){
  const m=milkFind(code);if(!m)return;
  const st=milkGetState(m);
  const dateStr=new Date(m.ts).toLocaleDateString('de-AT',{day:'2-digit',month:'2-digit',year:'numeric'});
  const storeIcon=m.store==='fridge'?'\u2744\ufe0f':m.store==='freezer'?'🧊':'🌡\ufe0f';
  const expDate=new Date(m.moves[m.moves.length-1].at+(MILK_LIMITS[m.moves[m.moves.length-1].to]||MILK_LIMITS.fridge));
  const expStr=expDate.toLocaleDateString('de-AT',{day:'2-digit',month:'2-digit',year:'numeric',hour:'2-digit',minute:'2-digit'});
  // Create label popup
  const div=document.createElement('div');
  div.style.cssText='position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,.5);z-index:9999;display:flex;align-items:center;justify-content:center';
  div.onclick=function(e){if(e.target===div)div.remove()};
  div.innerHTML='<div style="background:#fff;border-radius:12px;padding:24px;width:280px;text-align:center">'
    +'<div style="font-size:.65rem;color:#999;margin-bottom:4px">babyAlex Milchetikett</div>'
    +'<div style="border:3px solid #333;border-radius:8px;padding:16px;margin:8px 0">'
    +'<div style="font-family:Quicksand;font-weight:900;font-size:1.6rem;letter-spacing:2px">'+m.code+'</div>'
    +'<div style="margin:8px 0;font-size:.9rem">'+storeIcon+' '+m.ml+' ml</div>'
    +'<div style="font-size:.8rem;border-top:1px dashed #ccc;padding-top:8px;margin-top:8px">'
    +'📅 Abgepumpt: '+dateStr+'<br>'
    +'\u23f0 Verbrauchen bis:<br><b style="color:#C62828;font-size:1rem">'+expStr+'</b></div>'
    +'</div>'
    +'<button onclick="this.parentElement.parentElement.remove()" style="margin-top:8px;padding:8px 20px;border:none;border-radius:8px;background:var(--prim);color:#fff;font-weight:800;cursor:pointer">Schlie\u00dfen</button>'
    +' <button onclick="milkCopyLabel(\''+m.code+'\')" style="margin-top:8px;padding:8px 20px;border:none;border-radius:8px;background:var(--bg2);font-weight:800;cursor:pointer">📋 Kopieren</button>'
    +'</div>';
  document.body.appendChild(div);
}

function milkCopyLabel(code){
  const m=milkFind(code);if(!m)return;
  const dateStr=new Date(m.ts).toLocaleDateString('de-AT',{day:'2-digit',month:'2-digit',year:'numeric'});
  const expDate=new Date(m.moves[m.moves.length-1].at+(MILK_LIMITS[m.moves[m.moves.length-1].to]||MILK_LIMITS.fridge));
  const expStr=expDate.toLocaleDateString('de-AT',{day:'2-digit',month:'2-digit',year:'numeric',hour:'2-digit',minute:'2-digit'});
  const txt=m.code+' | '+m.ml+'ml | '+dateStr+' | bis: '+expStr;
  navigator.clipboard.writeText(txt).then(()=>toast('📋 Kopiert!')).catch(()=>toast('Kopieren nicht m\u00f6glich'));
}

// MILK PUSH NOTIFICATIONS
function milkSchedulePush(portion,ch){
  if(!('Notification' in window)||Notification.permission!=='granted')return;
  const name=ch?.name||'Baby';
  const lastMove=portion.moves[portion.moves.length-1];
  const storeType=lastMove.to;
  const ampel=MILK_AMPEL[storeType];
  if(!ampel)return;
  // Schedule yellow warning
  const yellowIn=ampel.yellow-(Date.now()-lastMove.at);
  if(yellowIn>0)setTimeout(()=>{
    const fresh=milkFind(portion.code);
    if(fresh&&fresh.status==='active')new Notification('🟡 Milch '+portion.code,{body:portion.ml+'ml bald verbrauchen!',tag:'milk-'+portion.code+'-y'});
  },yellowIn);
  // Schedule red warning
  const redIn=ampel.red-(Date.now()-lastMove.at);
  if(redIn>0)setTimeout(()=>{
    const fresh=milkFind(portion.code);
    if(fresh&&fresh.status==='active')new Notification('🔴 Milch '+portion.code,{body:portion.ml+'ml JETZT verbrauchen oder entsorgen!',tag:'milk-'+portion.code+'-r'});
  },redIn);
}

// Schedule pushes for all active portions on app start
function milkInitPush(){
  const ch=C();if(!ch?.milkStore)return;
  ch.milkStore.filter(m=>m.status==='active').forEach(m=>milkSchedulePush(m,ch));
}



// ===== TUTORIAL WALKTHROUGH =====
const TUT_STEPS=[
  {emoji:'\u2728',title:'tut_welcome_t',text:'tut_welcome',target:null,pos:'center'},
  {emoji:'😴',title:'tut_sleep_t',text:'tut_sleep',target:'btn-sleep',pos:'below'},
  {emoji:'🔮',title:'tut_pred_t',text:'tut_pred',target:'pred',pos:'below'},
  {emoji:'🤱',title:'tut_nurse_t',text:'tut_nurse',target:function(){return document.querySelector('.tc[onclick*="nurse"]')},pos:'above'},
  {emoji:'🧴',title:'tut_pump_t',text:'tut_pump',target:function(){return document.querySelector('.tc[onclick*="pump"]')},pos:'above'},
  {emoji:'📊',title:'tut_nav_t',text:'tut_nav',target:function(){return document.querySelector('.bnav')},pos:'above'},
  {emoji:'\u2699\ufe0f',title:'tut_settings_t',text:'tut_settings',target:function(){return document.querySelector('.ni[data-s="settings"]')},pos:'above'},
  {emoji:'🎉',title:'tut_done_t',text:'tut_done',target:null,pos:'center'}
];
let tutStep=0;

function tutStart(){
  nav('home');
  setTimeout(function(){
    tutStep=0;
    el('tut-overlay').classList.add('show');
    tutRender();
  },300);
}

function tutRender(){
  var step=TUT_STEPS[tutStep];
  var card=el('tut-card');
  var spot=el('tut-spotlight');
  el('tut-emoji').textContent=step.emoji;
  el('tut-title').textContent=t(step.title)||step.title;
  el('tut-text').textContent=t(step.text)||step.text;
  el('tut-step').textContent=(tutStep+1)+' / '+TUT_STEPS.length;
  var dots='';
  for(var i=0;i<TUT_STEPS.length;i++)dots+='<div class="dot'+(i===tutStep?' act':'')+'">'+'<'+'/div>';
  el('tut-dots').innerHTML=dots;
  el('tut-back').style.display=tutStep>0?'':'none';
  el('tut-skip').style.display=tutStep<TUT_STEPS.length-1?'':'none';
  el('tut-next').textContent=tutStep===TUT_STEPS.length-1?(t('tut_finish')||'🎉 Fertig!'):(t('tut_next')||'Weiter \u2192');
  el('tut-skip').textContent=t('tut_skip')||'\u00dcberspringen';
  el('tut-back').textContent='\u2190 '+(t('tut_back')||'Zur\u00fcck');
  var targetEl=null;
  if(step.target){
    targetEl=typeof step.target==='function'?step.target():el(step.target);
  }
  if(targetEl){
    var rect=targetEl.getBoundingClientRect();
    var pad=12;
    spot.style.display='block';
    spot.style.left=(rect.left-pad)+'px';
    spot.style.top=(rect.top-pad)+'px';
    spot.style.width=(rect.width+pad*2)+'px';
    spot.style.height=(rect.height+pad*2)+'px';
    targetEl.scrollIntoView({behavior:'smooth',block:'center'});
    setTimeout(function(){
      var sr=spot.getBoundingClientRect();
      var cw=card.offsetWidth||300;
      var ch=card.offsetHeight||200;
      var vw=window.innerWidth;
      var vh=window.innerHeight;
      var cx,cy;
      if(step.pos==='below'){
        cx=Math.max(20,Math.min(vw-cw-20,sr.left+sr.width/2-cw/2));
        cy=sr.bottom+16;
        if(cy+ch>vh-20){cy=sr.top-ch-16;card.className='arrow-bottom'}
        else{card.className='arrow-top'}
      }else{
        cx=Math.max(20,Math.min(vw-cw-20,sr.left+sr.width/2-cw/2));
        cy=sr.top-ch-16;
        if(cy<20){cy=sr.bottom+16;card.className='arrow-top'}
        else{card.className='arrow-bottom'}
      }
      card.style.left=cx+'px';
      card.style.top=cy+'px';
    },100);
  }else{
    spot.style.display='none';
    card.className='';
    card.style.left='calc(50% - 150px)';
    card.style.top='calc(50% - 100px)';
  }
}

function tutNav(dir){
  tutStep+=dir;
  if(tutStep>=TUT_STEPS.length){tutEnd();return}
  if(tutStep<0)tutStep=0;
  tutRender();
}
function tutSkip(){tutEnd()}
function tutEnd(){
  el('tut-overlay').classList.remove('show');
  localStorage.setItem('bs3_tut_done','1');
}
function tutAutoStart(){
  if(localStorage.getItem('bs3_tut_done'))return;
  setTimeout(function(){tutStart()},1500);
}

