// ===== HISTORY & BACKUP =====
let histFilter='all';
function showHistory(){el('history-modal').classList.add('act');renderHist()}
function filterHist(type,btn){histFilter=type;
  el('history-modal').querySelectorAll('.pill').forEach(p=>p.classList.remove('sel'));
  if(btn)btn.classList.add('sel');renderHist()}
function renderHist(){
  const c=C();if(!c)return;
  let entries=[...c.entries].sort((a,b)=>b.ts-a.ts);
  if(histFilter!=='all')entries=entries.filter(e=>e.type===histFilter);
  el('hist-count').textContent=`${entries.length} ${t('hi_n')}${histFilter!=='all'?' (gefiltert)':''}`;
  const ic={sleep:'😴',feed:'🍼',diaper:'🧷',note:'📝',nightwake:'🌙'};
  const lb={sleep:e=>e.sub==='night'?t('tl_ns'):t('tl_nap'),
    feed:e=>({breast:t('f_breast'),bottle:t('f_bottle'),solid:t('f_solid')}[e.sub]||t('h_feed')),
    diaper:e=>({wet:t('f_wet'),dirty:t('f_dirty'),both:t('f_both')}[e.sub]||t('h_diaper')),
    note:e=>e.text||t('tl_note'),nightwake:e=>({hunger:t('f_hunger'),diaper:t('h_diaper'),comfort:t('f_comfort')}[e.sub])||'Aufwachen'};
  if(!entries.length){el('hist-list').innerHTML='<div style="text-align:center;color:var(--txt-m);padding:20px">'+t('cal_none')+'</div>';return}
  let lastDate='';
  el('hist-list').innerHTML=entries.map(e=>{
    const d=new Date(e.ts);const ds=d.toLocaleDateString('de-AT',{weekday:'short',day:'numeric',month:'short'});
    const tm=d.toLocaleTimeString('de-AT',{hour:'2-digit',minute:'2-digit'});
    const dur=e.dur?` · ${e.dur}m`:'';const ml=e.ml?` · ${e.ml}ml`:'';
    let header='';if(ds!==lastDate){lastDate=ds;header=`<div style="font-weight:700;font-size:.85rem;color:var(--pri-d);margin:12px 0 6px;border-bottom:1px solid var(--brd);padding-bottom:4px">${ds}</div>`}
    return`${header}<div style="display:flex;align-items:center;gap:10px;padding:8px 0;border-bottom:1px solid var(--brd)"><span style="font-size:1.2rem">${ic[e.type]||'📝'}</span><div style="flex:1"><div style="font-weight:600;font-size:.85rem">${(lb[e.type]||lb.note)(e)}${dur}${ml}</div><div style="font-size:.75rem;color:var(--txt-m)">${tm}</div></div><button onclick="delE('${e.id}');renderHist()" style="background:none;border:none;color:var(--err);cursor:pointer;font-size:1rem">✕</button></div>`}).join('')}

function backupData(){
  const data=localStorage.getItem('bs3');if(!data){toast('⚠️ '+t('cal_none'));return}
  const c=C();const name=c?c.name:'backup';
  dl(data,'application/json',`babyalex_${name}_${new Date().toISOString().split('T')[0]}.json`);
  toast(t('t_bksave'))}

function restoreData(ev){
  const file=ev.target.files[0];if(!file)return;
  if(!confirm(t('t_restore')+'schrieben!'))return;
  const r=new FileReader();
  r.onload=e=>{try{const d=JSON.parse(e.target.result);
    if(!d.children&&!Array.isArray(d)){toast(t('t_bkinv'));return}
    localStorage.setItem('bs3',JSON.stringify(d));location.reload()}
    catch(err){toast('❌ Fehler beim Laden')}};
  r.readAsText(file)}

function compactData(){
  const c=C();if(!c){toast('⚠️ Kein Kind');return}
  const before=c.entries.length;
  // Remove duplicates (same type+timestamp within 1 min)
  const seen=new Set();
  c.entries=c.entries.filter(e=>{const key=e.type+'_'+Math.floor(e.ts/60000);if(seen.has(key))return false;seen.add(key);return true});
  // Remove entries older than 90 days without sleep data
  const cutoff=Date.now()-90*24*36e5;
  c.entries=c.entries.filter(e=>e.ts>cutoff||e.type==='sleep');
  const after=c.entries.length;
  save();toast(`🗜️ ${before-after} ${t('t_comp')} (${after} ${t('t_comp2')})`)}

// ===== FAMILY SYNC =====
const SYNC_API = localStorage.getItem('bs3_api') || 'https://babyschlaf-sync-production.up.railway.app';
function deviceId(){let d=localStorage.getItem('bs3_did');if(!d){d=crypto.randomUUID();localStorage.setItem('bs3_did',d)}return d}
function syncState(){const s=localStorage.getItem('bs3_sync');return s?JSON.parse(s):null}
function setSyncState(v){localStorage.setItem('bs3_sync',JSON.stringify(v))}

async function createFamily(){
  try{
    toast(t('t_fcre'));
    const r=await fetch(SYNC_API+'/api/family/create',{method:'POST'});
    const d=await r.json();
    if(d.ok){setSyncState({code:d.code,joined:Date.now(),lastSync:0});showSyncUI();toast(t('t_fcred'));syncNow()}
    else toast('❌ Fehler: '+d.error);
  }catch(e){toast('❌ '+t('t_off'))}
}

async function joinFamily(){
  const code=el('join-code').value.trim().toUpperCase();
  if(!code||code.length!==6){toast('⚠️ Bitte 6-stelligen Code eingeben');return}
  try{
    toast(t('t_fjoi'));
    const r=await fetch(SYNC_API+'/api/family/join',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({code})});
    const d=await r.json();
    if(d.ok){setSyncState({code:d.code,joined:Date.now(),lastSync:0});showSyncUI();toast(t('t_fjoid'));syncNow()}
    else toast('❌ '+d.error);
  }catch(e){toast('❌ '+t('t_off'))}
}

async function syncNow(silent){
  const st=syncState();if(!st)return;
  try{
    if(!silent)el('sync-status').textContent='⏳ Synce...';
    const c=C();
    // Push local data + deleted entries as tombstones
    const entries=(c?.entries||[]).map(e=>({...e,_ts:Math.floor((e.ts||Date.now())/1000)}));
    const deletedEntries=(S._deletedIds||[]).map(d=>({id:d.id,_deleted:true,_ts:Math.floor(d.ts/1000)}));
    const allEntries=[...entries,...deletedEntries];
    const babies=JSON.parse(localStorage.getItem('bs3'))||[];
    await fetch(SYNC_API+'/api/sync/push',{method:'POST',headers:{'Content-Type':'application/json'},
      body:JSON.stringify({code:st.code,device_id:deviceId(),babies:Array.isArray(babies)?babies:[babies],entries:allEntries})});
    // Pull remote data
    const pr=await fetch(SYNC_API+'/api/sync/pull',{method:'POST',headers:{'Content-Type':'application/json'},
      body:JSON.stringify({code:st.code,since:st.lastSync||0})});
    const pd=await pr.json();
    let merged=0;
    if(pd.ok&&pd.entries.length>0){
      const local=c?.entries||[];
      const map=new Map(local.map(e=>[e.id,e]));
      // Build set of locally deleted IDs to prevent re-sync
      const deletedSet=new Set((S._deletedIds||[]).map(d=>d.id));
      pd.entries.forEach(e=>{
        if(e._deleted){map.delete(e.id);deletedSet.add(e.id);
          // Also track remotely deleted entries locally
          if(!S._deletedIds)S._deletedIds=[];
          if(!(S._deletedIds||[]).find(d=>d.id===e.id))S._deletedIds.push({id:e.id,ts:Date.now()})}
        else if(deletedSet.has(e.id)){/* skip - locally or remotely deleted */}
        else if(!map.has(e.id)||e.ts>map.get(e.id).ts){map.set(e.id,e);merged++}
      });
      if(c){c.entries=[...map.values()];
        // Save without triggering sync again
        try{localStorage.setItem('bs3',JSON.stringify(S));
          localStorage.setItem('bs3_deleted',JSON.stringify(S._deletedIds||[]))}catch(e){}
        updateAll()}
    }
    if(pd.devices){pd.devices.forEach(dev=>{if(dev.device_id===deviceId())return})}
    st.lastSync=pd.server_time||Math.floor(Date.now()/1000);
    setSyncState(st);
    const syncEl=el('sync-status');
    if(syncEl)syncEl.textContent='✅ '+new Date().toLocaleTimeString('de-AT',{hour:'2-digit',minute:'2-digit'});
    const infoEl=el('sync-info');
    if(infoEl)infoEl.textContent=merged>0?`${merged} ${t('t_nsync')}`:t('sync_ok');
    if(merged>0&&!silent)toast(`🔄 ${merged} ${t('t_nsync')}`);
    if(merged>0&&silent)notifSync(merged);
  }catch(e){
    const syncEl=el('sync-status');
    if(syncEl&&!silent)syncEl.textContent='❌ Offline';
    console.error('Sync:',e)}
}

// Auto-sync: poll every 30s when synced, pull changes from partner
let _syncInterval=null;
function startAutoSync(){
  if(_syncInterval)clearInterval(_syncInterval);
  if(!syncState())return;
  _syncInterval=setInterval(()=>syncNow(true),30000);
}
// Sync when app comes to foreground (tab/app switch)
document.addEventListener('visibilitychange',()=>{
  if(!document.hidden&&syncState())syncNow(true)});
// Sync on page load
window.addEventListener('load',()=>{if(syncState())setTimeout(()=>syncNow(true),1000)});

function showSyncUI(){
  const st=syncState();
  if(st){el('sync-off').style.display='none';el('sync-on').style.display='block';el('sync-code').textContent=st.code;
    if(st.lastSync>0)el('sync-status').textContent='✅ '+new Date(st.lastSync*1000).toLocaleTimeString('de-AT',{hour:'2-digit',minute:'2-digit'});
    startAutoSync();
  }else{el('sync-off').style.display='block';el('sync-on').style.display='none';if(_syncInterval)clearInterval(_syncInterval)}
}

function copyCode(){const st=syncState();if(st){navigator.clipboard?.writeText(st.code);toast('📋 Code kopiert: '+st.code)}}

function leaveFamily(){if(confirm(t('t_fleave'))){localStorage.removeItem('bs3_sync');showSyncUI();toast(t('t_fleft'))}}

// Auto-sync every 5 minutes when connected
setInterval(()=>{if(syncState())syncNow()},5*60*1000);

// ===== INIT =====
function init(){
  load();
  const obEl=el('onboarding');
  if(!S.children.length){if(obEl)obEl.classList.remove('hid')}
  else{if(obEl)obEl.classList.add('hid');
    if(S.nightMode)applyNight();
    updateAll();renderCourse()}
  renderSounds();autoNightMode();showSyncUI();initLang();
  if(syncState())setTimeout(syncNow,2000);
  setInterval(()=>{if(C())updatePred()},15000);
  const nwm=el('nw-modal');if(nwm)nwm.addEventListener('click',e=>{if(e.target.id==='nw-modal')e.target.classList.remove('act')});
  if('serviceWorker' in navigator)navigator.serviceWorker.register('sw.js').catch(()=>{});
}

function initLang(){
  // Update onboarding lang-grid button styles
  document.querySelectorAll('#lang-grid [data-lc]').forEach(b=>{
    const sel=b.dataset.lc===_lang;
    b.style.background=sel?'var(--pri)':'var(--card)';
    b.style.color=sel?'#fff':'var(--txt)';
  });
  // Render settings lang list
  const list=el('lang-list');
  if(list){list.innerHTML=LANGS.map(l=>'<button onclick="setLang(\''+l.code+'\');closeForm()" style="background:'+(l.code===_lang?'var(--pri)':'var(--card)')+';color:'+(l.code===_lang?'#fff':'var(--txt)')+';border:1px solid var(--brd);border-radius:var(--rs);padding:10px;font-size:.85rem;cursor:pointer;text-align:left">'+l.flag+' '+l.name+'</button>').join('')}
  applyLang();
}
function openLangPicker(){const m=el('fm-lang');if(m){m.classList.add('act');initLang()}}
init();